onClick:
{{
  (async () => {
    const row = SearchResultTable.selectedRow;

    if (!row || !row.asset_id) {
      showAlert("Select an asset first", "warning");
      return;
    }

    if (row.status_name !== "Available for Sale") {
      showAlert("Asset is not available for sale", "warning");
      return;
    }

    // Check not already staged
    const current = appsmith.store.saleList || [];
    const alreadyAdded = current.find(i => i.asset_id === row.asset_id);
    if (alreadyAdded) {
      showAlert("Asset already added to this sale", "warning");
      return;
    }

    // Stage item in store only — no DB insert yet
    await storeValue("saleList", current.concat({
      asset_id: row.asset_id,
      asset_ref: row.asset_ref,
      item_type_name: row.item_type_name,
      make_name: row.make_name,
      model_name: row.model_name,
      serial_number: row.serial_number,
      sell_price: row.sell_price
    }));

    showAlert("Item staged — click Process Order to confirm", "info");
  })()
}}
